function stripAuth(url) {
  const authIndex = url.indexOf('@');
  if (authIndex !== -1) {
    const auth = url.substring(0, authIndex);
    const usernamePasswordIndex = auth.indexOf(':');
    if (usernamePasswordIndex !== -1) {
      const username = auth.substring(0, usernamePasswordIndex);
      const password = auth.substring(usernamePasswordIndex + 1);
      return url.replace(`${username}:${password}@`, '@');
