Here's a simple example of how to implement the MVC pattern in Python:

```python
# Model
class Book:
    def __init__(self, title, author):
        self.title = title
        self.author = author

    def get_details(self):
        return f"Title: {self.title}, Author: {self.author}"

# View
class BookView:
    def display_book(self, book):
        print(book.get_details())

# Controller
class BookController:
    def __init__(self):
        self.model = Book("Harry Potter", "J.K. Rowling")

    def display_book(self):
        view = BookView()
        view.display_book(self.model)

# Main Program
if __name__ == "__main__":
    controller = BookController()

